mapper.select:
select s.*, c.name clazzName from student s
left join clazz c on s.clazz_id = c.id

    
        and s.id = #{id}
    
    
        and s.name like concat('%', #{name}, '%')
    
    
        and s.no like concat('%', #{no}, '%')
    
    
        and s.gender = #{gender}
    
    
        and s.phone like concat('%', #{phone}, '%')
    
    
        and s.id_card like concat('%', #{idCard}, '%')
    
    
        and s.is_college = #{isCollege}
    
    
        and s.address like concat('%', #{address}, '%')
    
    
        and s.degree = #{degree}
    
    
        and s.graduation_date = #{graduationDate}
    
    
        and s.clazz_id = #{clazzId}
    
    
        and s.violation_count = #{violationCount}
    
    
        and s.violation_score = #{violationScore}
    
    
        and s.create_time = #{createTime}
    
    
        and s.update_time = #{updateTime}
    
    
        and c.clazz_name like concat('%', #{clazzName}, '%')
    

order by s.update_time desc

mapper.update:
update student
name = #{name}, no = #{no}, gender = #{gender}, phone = #{phone}, degree = #{degree}, id_card = #{idCard}, is_college = #{isCollege}, address = #{address}, graduation_date = #{graduationDate}, violation_count = #{violationCount}, violation_score = #{violationScore}, clazz_id = #{clazzId}, update_time = #{updateTime}
where id = #{id}
